 /*	case SNDCTL_DSP_CHANNELS: ( == SOUND_PCM_WRITE_CHANNELS) */
-		if (*arg_i == 1 || *arg_i == 2) {
-			tmp = 0;
-			*arg_i = (*arg_i == 2)? AFMT_STEREO : 0;
-	  		if (wrch) {
-				CHN_LOCK(wrch);
-				ret = chn_setformat(wrch, (wrch->format
 				& ~AFMT_STEREO) | *arg_i);
-				tmp = (wrch->format & AFMT_STEREO)? 2 :
 				1;
-				CHN_UNLOCK(wrch);
-			}
-			if (rdch && ret == 0) {
-				CHN_LOCK(rdch);
-				ret = chn_setformat(rdch, (rdch->format
 				& ~AFMT_STEREO) | *arg_i);
-				if (tmp == 0)
-					tmp = (rdch->format &
 					AFMT_STEREO)? 2 : 1;
-				CHN_UNLOCK(rdch);
-			}
-			*arg_i = tmp;
-		} else
-			*arg_i = 0;
+		if (*arg_i != 1 && *arg_i != 2) {
+                        *arg_i = 2;
+                }
+                tmp = 0;
+                *arg_i = (*arg_i == 2)? AFMT_STEREO : 0;
+                if (wrch) {
+			CHN_LOCK(wrch);
+			ret = chn_setformat(wrch, (wrch->format &
~AFMT_STEREO) | *arg_i);
+			tmp = (wrch->format & AFMT_STEREO)? 2 : 1;
+			CHN_UNLOCK(wrch);
+		}
+		if (rdch && ret == 0) {
+			CHN_LOCK(rdch);
+			ret = chn_setformat(rdch, (rdch->format &
~AFMT_STEREO) | *arg_i);
+			if (tmp == 0)
+				tmp = (rdch->format & AFMT_STEREO)? 2 :
1;
+			CHN_UNLOCK(rdch);
+		}
+		*arg_i = tmp;
 		break;

     	case SOUND_PCM_READ_CHANNELS:
